class Solution {
public:
    int kIncreasing(vector<int>& arr, int k) {
        int n = arr.size();
        int res = 0;
        for (int start = 0; start < k; ++start) {
            vector<int> sub;
            for (int i = start; i < n; i += k) {
                sub.push_back(arr[i]);
            }
            if (sub.empty()) continue;
            vector<int> tails;
            for (int x : sub) {
                int left = 0, right = tails.size();
                while (left < right) {
                    int mid = (left + right) / 2;
                    if (tails[mid] > x) {
                        right = mid;
                    } else {
                        left = mid + 1;
                    }
                }
                if (left == tails.size()) {
                    tails.push_back(x);
                } else {
                    tails[left] = x;
                }
            }
            res += sub.size() - tails.size();
        }
        return res;
    }
};

